export const GenericCardRender = ({ id }: { id: string }) => {
    const data = PRD_DATA[id];

    // Fallback if data is missing
    if (!data) return <div className="p-6 h-56 flex items-center justify-center text-gray-400 font-mono text-xs bg-white">[STUB: {id}]</div>;

    // A stylized preview based on style DNA
    return (
        <div className="h-56 w-full relative overflow-hidden flex flex-col items-center justify-center p-6 bg-white" style={{ borderRadius: data.specs.radius }}>
            {/* Background Hint */}
            <div className="absolute inset-0 opacity-5 pointer-events-none" style={{ backgroundColor: data.specs.colors.split(',')[0] }}></div>

            {/* Visual Representative Element */}
            <div 
                className="w-32 h-20 flex items-center justify-center border-2 border-gray-200 transition-all duration-300 group-hover:scale-105"
                style={{ 
                    borderRadius: data.specs.radius, 
                    boxShadow: data.specs.shadow.includes('4px') ? '4px 4px 0px 0px #000' : '0 10px 15px -3px rgba(0,0,0,0.1)',
                    borderColor: id === 'terminal' ? '#00FF00' : (id === 'cyberpunk' ? '#fcee0a' : '#E5E7EB'),
                    backgroundColor: id === 'terminal' ? '#000' : '#FFF'
                }}
            >
                <div className="text-xs font-bold px-2 text-center" style={{ fontFamily: data.specs.font, color: id === 'terminal' ? '#00FF00' : '#000' }}>
                    {data.name.split(' ')[0]}
                </div>
            </div>

            {/* Labels */}
            <div className="mt-4 flex flex-col items-center gap-1">
                <div className="text-[10px] text-gray-400 font-mono uppercase tracking-widest">{data.specs.font}</div>
                <div className="flex gap-1">
                    {data.specs.colors.split(',').slice(0, 3).map((c, i) => (
                        <div key={i} className="w-2 h-2 rounded-full border border-gray-100" style={{ backgroundColor: c.trim() }}></div>
                    ))}
                </div>
            </div>

            {/* Aesthetic Polish per Tier */}
            {id === 'cyberpunk' && <div className="absolute top-0 left-0 w-full h-full border-[1px] border-yellow-400/20 pointer-events-none"></div>}
            {id === 'retro-os' && <div className="absolute inset-0 border-t-2 border-l-2 border-white border-r-2 border-b-2 border-gray-600 pointer-events-none"></div>}
        </div>
    );
};

