                                        <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold uppercase ${item.tierColorClass}`}>
                                            {item.tier}
                                        </span>
                                    </div>

                                    {/* Canvas Area */}
                                    <div className={isFusionMode ? 'pointer-events-none opacity-90' : ''}>
                                        {renderCardContent(item.id)}
                                    </div>

                                    {/* Footer */}
                                    <div className="p-5 flex-grow flex flex-col justify-end bg-white relative z-10">
                                        <p className="text-xs text-gray-500 mb-2 font-medium leading-relaxed line-clamp-2">{item.description}</p>
                                        <p className="text-[10px] text-gray-400 mb-4 uppercase tracking-wider line-clamp-1">{item.application}</p>

                                        {!isFusionMode && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); setActiveModalId(item.id); }}
                                                className="w-full text-center font-bold py-3 rounded-xl border border-gray-200 text-xs transition active:scale-95 hover:bg-black hover:text-white hover:border-black uppercase tracking-widest"
                                            >
                                                查看技术规范
                                            </button>
                                        )}
                                        {isFusionMode && (
                                            <div className={`w-full text-center py-3 font-bold rounded-xl border transition-colors text-xs uppercase tracking-widest ${isSelected ? 'bg-purple-600 text-white border-purple-600' : 'text-purple-600 bg-purple-50 border-purple-100'}`}>
                                                {isSelected ? '已选择' : '点击选择'}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </main>

            {/* Fusion FAB */}
            {isFusionMode && selectedStyleIds.length > 0 && (
                <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 z-40 animate-slide-up">
                    <button 
                        onClick={startFusion}
                        disabled={selectedStyleIds.length < 2 || isFusing}
                        className={`
                            flex items-center gap-3 px-10 py-5 rounded-full shadow-2xl font-black text-sm uppercase tracking-widest transition-all
                            ${selectedStyleIds.length < 2 
                                ? 'bg-gray-800 text-gray-500 cursor-not-allowed' 
                                : 'bg-black text-white hover:scale-105 active:scale-95 ring-8 ring-black/10'
                            }
                        `}
                    >
                        {isFusing ? '融合计算中...' : `融合 ${selectedStyleIds.length} 种 DNA`}
                    </button>
                </div>
            )}

            {/* Modals */}
            {activeModalId && <PrdModal id={activeModalId} onClose={() => setActiveModalId(null)} />}
            {fusionResult && <FusionResultModal result={fusionResult} isSaved={!!savedFusions.find(f => f.id === fusionResult.id)} onSave={saveFusion} onClose={() => setFusionResult(null)} />}
            {projectResult && <ProjectPrdModal project={projectResult} isSaved={!!savedProjects.find(p => p.id === projectResult.id)} onSave={saveProject} onClose={() => setProjectResult(null)} />}

            {/* Idea Input (Simplified) */}
            {showIdeaInput && (
                <div className="fixed inset-0 bg-black/60 z-[60] flex items-center justify-center p-4 backdrop-blur-sm">
                    <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 animate-scale-in">
