export const SpatialCard = () => {
    const cardRef = useRef<HTMLDivElement>(null);
    const [mouse, setMouse] = useState({ x: 0, y: 0 });
    const handleMouseMove = (e: React.MouseEvent) => {
        if (!cardRef.current) return;
        const rect = cardRef.current.getBoundingClientRect();
        setMouse({ x: e.clientX - rect.left, y: e.clientY - rect.top });
    };
    return (
        <div className="h-56 bg-[#09090b] flex items-center justify-center relative p-6 group perspective-1000" onMouseMove={handleMouseMove}>
            <div ref={cardRef} className="relative w-full h-full bg-zinc-900/50 border border-white/10 rounded-3xl overflow-hidden shadow-2xl transition-transform duration-100 ease-out group-hover:rotate-x-2 group-hover:rotate-y-2" style={{ backdropFilter: 'blur(20px)', transformStyle: 'preserve-3d' }}>
                <div className="absolute inset-0 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-300" style={{ background: `radial-gradient(600px circle at ${mouse.x}px ${mouse.y}px, rgba(255,255,255,0.06), transparent 40%)` }}></div>
