    // Existing T0
    BentoCard, 
    GlassCard, 
    BrutalCard, 
    CassetteCard, 
    NeuCard,
    DosCard,
    Win95Card,
    GenericCardRender,
    LiquidGlassCard,
    AiAbstractCard,
    BlueprintCadCard,
    AnthropicCard
} from './components/InteractiveCards';

const App: React.FC = () => {
    // --- State ---
    const [activeModalId, setActiveModalId] = useState<string | null>(null);
    const [isFusionMode, setIsFusionMode] = useState(false);
    const [selectedStyleIds, setSelectedStyleIds] = useState<string[]>([]);
    const [isFusing, setIsFusing] = useState(false);
    const [fusionResult, setFusionResult] = useState<FusionResult | null>(null);
    const [savedFusions, setSavedFusions] = useState<FusionResult[]>([]);
    const [showCollection, setShowCollection] = useState(false);

    // --- Project Genesis State ---
    const [showIdeaInput, setShowIdeaInput] = useState(false);
    const [userIdea, setUserIdea] = useState('');
    const [isGeneratingProject, setIsGeneratingProject] = useState(false);
    const [generationStatus, setGenerationStatus] = useState<string>(''); 
    const [projectResult, setProjectResult] = useState<ProjectPrd | null>(null);
    const [savedProjects, setSavedProjects] = useState<ProjectPrd[]>([]);
    const [collectionTab, setCollectionTab] = useState<'styles' | 'projects'>('styles');

    // --- Actions ---

    const toggleSelection = (id: string) => {
        if (selectedStyleIds.includes(id)) {
            setSelectedStyleIds(selectedStyleIds.filter(sid => sid !== id));
        } else {
            if (selectedStyleIds.length >= 3) {
                alert("Please select max 3 styles for fusion.");
                return;
            }
            setSelectedStyleIds([...selectedStyleIds, id]);
        }
    };

    const handleCardClick = (id: string) => {
        if (isFusionMode) {
            toggleSelection(id);
        }
    };

    const startFusion = async () => {
        if (selectedStyleIds.length < 2) return;
        setIsFusing(true);
        try {
            const result = await fuseStyles(selectedStyleIds, STYLE_ITEMS);
            setFusionResult(result);
        } catch (e) {
            alert("Fusion failed. Please try again.");
        } finally {
            setIsFusing(false);
        }
    };

    const handleCreateProject = async () => {
        if (!userIdea.trim()) return;
        setShowIdeaInput(false);
        setIsGeneratingProject(true);
        setGenerationStatus("正在初始化 Genesis 引擎...");

        try {
            const prd = await generateProjectPrd(
                userIdea, 
                STYLE_ITEMS,
                (status) => setGenerationStatus(status)
            );
            setProjectResult(prd);
        } catch (e) {
            alert("Failed to generate project. Please try again.");
        } finally {
            setIsGeneratingProject(false);
            setGenerationStatus("");
        }
    };

    const saveFusion = (result: FusionResult) => {
        if (!savedFusions.find(f => f.id === result.id)) {
            setSavedFusions([result, ...savedFusions]);
        }
    };

    const saveProject = (result: ProjectPrd) => {
        if (!savedProjects.find(p => p.id === result.id)) {
            setSavedProjects([result, ...savedProjects]);
        }
    };

    // Component Factory
    const renderCardContent = (id: string) => {
        switch(id) {
            // WAVE 2 T0 (New Hidden Gems)
            case 'holographic': return <HolographicCard />;
            case 'dither': return <DitherCard />;
            case 'risograph': return <RisographCard />;
            case 'ethereal': return <EtherealCard />;

            // WAVE 1 T0
            case 'chromium': return <ChromiumCard />;
            case 'kinetic': return <KineticCard />;
            case 'spatial': return <SpatialCard />;
            case 'dreamcore': return <DreamcoreCard />;

            // EXISTING T0
            case 'anthropic-serif': return <AnthropicCard />;
            case 'ai-abstract': return <AiAbstractCard />;
            case 'blueprint-cad': return <BlueprintCadCard />;
            case 'liquid-glass': return <LiquidGlassCard />;

            // CLASSICS
            case 'bento': return <BentoCard />;
            case 'glass': return <GlassCard />;
            case 'brutal': return <BrutalCard />;
            case 'cassette': return <CassetteCard />;
            case 'neu': return <NeuCard />;
            case 'dos': return <DosCard />;
            case 'win95': return <Win95Card />;

            default: return <GenericCardRender id={id} />;
        }
    };

    return (
        <div className="min-h-screen pb-20 relative bg-gray-50">
             {/* Header */}
            <header className="bg-white border-b border-gray-200 sticky top-0 z-50 backdrop-blur-md bg-white/90">
                <div className="max-w-7xl mx-auto py-4 px-4 sm:px-6 lg:px-8 flex flex-col md:flex-row justify-between items-center gap-4">
                    <div>
                        <h1 className="text-2xl font-black tracking-tight text-gray-900 cursor-pointer flex items-center gap-2" onClick={() => setShowCollection(false)}>
                            UI Style Museum 
                            <span className="text-[10px] bg-black text-white px-2 py-0.5 rounded font-mono uppercase">2025 Edition</span>
                        </h1>
                        <p className="text-[11px] text-gray-500 font-medium uppercase tracking-widest mt-1">
                            {STYLE_ITEMS.length} Curated Styles • Avant-Garde • AI Fusion
                        </p>
                    </div>

                    <div className="flex items-center gap-3">
                        <button 
                            onClick={() => { setShowIdeaInput(true); setShowCollection(false); }}
                            className="bg-black text-white px-5 py-2.5 rounded-full text-xs font-bold shadow-lg hover:shadow-xl hover:scale-105 transition active:scale-95 flex items-center gap-2"
                        >
                            ✨ 创建新项目
                        </button>

                        <div className="h-6 w-px bg-gray-200 mx-1"></div>

                        <button 
                            onClick={() => { setShowCollection(!showCollection); setIsFusionMode(false); }}
                            className={`px-4 py-2.5 rounded-full text-xs font-bold transition flex items-center gap-2 ${showCollection ? 'bg-indigo-600 text-white' : 'bg-white border border-gray-200 text-gray-700 hover:bg-gray-50'}`}
                        >
                            📂 收藏
                        </button>

                        <button 
                            onClick={() => { setIsFusionMode(!isFusionMode); setShowCollection(false); setSelectedStyleIds([]); }}
                            className={`px-4 py-2.5 rounded-full text-xs font-bold transition flex items-center gap-2 border ${
                                isFusionMode 
                                ? 'bg-purple-600 text-white border-purple-600' 
                                : 'bg-white border-gray-200 text-gray-700 hover:border-purple-400'
                            }`}
                        >
                            🧬 实验室
                        </button>
                    </div>
                </div>
            </header>

            <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
                {showCollection ? (
                    <div className="animate-fade-in">
                        {/* Collection View */}
                        <div className="text-center py-20">
                            <h2 className="text-2xl font-bold">我的收藏</h2>
                            <p className="text-gray-500 mt-2">查看您保存的 {savedFusions.length} 个融合风格和 {savedProjects.length} 个项目。</p>
                        </div>
                    </div>
                ) : (
                    /* Standard Grid */
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-3 gap-8">
                        {STYLE_ITEMS.map((item) => {
                            const isSelected = selectedStyleIds.includes(item.id);
                            // New Wave 2 T0
                            const isNewWave = ['holographic', 'dither', 'risograph', 'ethereal'].includes(item.id);
                            // Wave 1 T0
                            const isAvantGarde = ['chromium', 'kinetic', 'spatial', 'dreamcore'].includes(item.id);

                            return (
                                <div 
                                    key={item.id} 
                                    onClick={() => handleCardClick(item.id)}
                                    className={`
                                        bg-white rounded-[2rem] overflow-hidden flex flex-col group transition-all duration-300 relative
                                        ${isFusionMode ? 'cursor-pointer' : ''}
                                        ${isSelected 
                                            ? 'ring-4 ring-purple-500 transform scale-[1.02] shadow-2xl z-10' 
                                            : 'border border-gray-100 hover:shadow-xl hover:translate-y-[-4px]'
                                        }
                                    `}
                                >
                                    {/* Labels */}
                                    {isNewWave && !isFusionMode && (
                                        <div className="absolute top-4 left-4 z-20 bg-gradient-to-r from-pink-500 to-purple-600 text-white text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wider animate-pulse shadow-lg">
                                            Hidden Gem 💎
                                        </div>
                                    )}
                                    {isAvantGarde && !isNewWave && !isFusionMode && (
                                        <div className="absolute top-4 left-4 z-20 bg-black text-white text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wider">
                                            Trend 2025
                                        </div>
                                    )}

                                    {/* Selection Indicator */}
                                    {isSelected && (
                                        <div className="absolute top-4 right-4 z-20 w-8 h-8 bg-purple-600 rounded-full flex items-center justify-center text-white shadow-lg animate-bounce">✓</div>
                                    )}

                                    {/* Card Header */}
                                    <div className="px-5 py-4 border-b border-gray-50 bg-white flex justify-between items-center">
                                        <span className="font-bold text-sm text-gray-900 truncate pr-2 tracking-tight">
                                            {item.title}
                                        </span>
                                        <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold uppercase ${item.tierColorClass}`}>
                                            {item.tier}
                                        </span>
                                    </div>

                                    {/* Canvas Area */}
                                    <div className={isFusionMode ? 'pointer-events-none opacity-90' : ''}>
                                        {renderCardContent(item.id)}
                                    </div>

                                    {/* Footer */}
                                    <div className="p-5 flex-grow flex flex-col justify-end bg-white relative z-10">
                                        <p className="text-xs text-gray-500 mb-2 font-medium leading-relaxed line-clamp-2">{item.description}</p>
                                        <p className="text-[10px] text-gray-400 mb-4 uppercase tracking-wider line-clamp-1">{item.application}</p>

                                        {!isFusionMode && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); setActiveModalId(item.id); }}
                                                className="w-full text-center font-bold py-3 rounded-xl border border-gray-200 text-xs transition active:scale-95 hover:bg-black hover:text-white hover:border-black uppercase tracking-widest"
                                            >
                                                查看技术规范
                                            </button>
                                        )}
                                        {isFusionMode && (
                                            <div className={`w-full text-center py-3 font-bold rounded-xl border transition-colors text-xs uppercase tracking-widest ${isSelected ? 'bg-purple-600 text-white border-purple-600' : 'text-purple-600 bg-purple-50 border-purple-100'}`}>
                                                {isSelected ? '已选择' : '点击选择'}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </main>

            {/* Fusion FAB */}
            {isFusionMode && selectedStyleIds.length > 0 && (
                <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 z-40 animate-slide-up">
                    <button 
                        onClick={startFusion}
                        disabled={selectedStyleIds.length < 2 || isFusing}
                        className={`
                            flex items-center gap-3 px-10 py-5 rounded-full shadow-2xl font-black text-sm uppercase tracking-widest transition-all
                            ${selectedStyleIds.length < 2 
                                ? 'bg-gray-800 text-gray-500 cursor-not-allowed' 
                                : 'bg-black text-white hover:scale-105 active:scale-95 ring-8 ring-black/10'
                            }
                        `}
                    >
                        {isFusing ? '融合计算中...' : `融合 ${selectedStyleIds.length} 种 DNA`}
                    </button>
                </div>
            )}

            {/* Modals */}
            {activeModalId && <PrdModal id={activeModalId} onClose={() => setActiveModalId(null)} />}
            {fusionResult && <FusionResultModal result={fusionResult} isSaved={!!savedFusions.find(f => f.id === fusionResult.id)} onSave={saveFusion} onClose={() => setFusionResult(null)} />}
            {projectResult && <ProjectPrdModal project={projectResult} isSaved={!!savedProjects.find(p => p.id === projectResult.id)} onSave={saveProject} onClose={() => setProjectResult(null)} />}

            {/* Idea Input (Simplified) */}
            {showIdeaInput && (
                <div className="fixed inset-0 bg-black/60 z-[60] flex items-center justify-center p-4 backdrop-blur-sm">
                    <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 animate-scale-in">
                        <h3 className="text-2xl font-black text-gray-900 mb-2 tracking-tighter">PROJECT GENESIS</h3>
                        <p className="text-sm text-gray-500 mb-6 font-medium">输入创意，AI 将基于 2025 趋势库为您生成完整 PRD。</p>
                        <textarea 
                            className="w-full h-32 p-4 bg-gray-50 border-none rounded-2xl focus:ring-2 focus:ring-black resize-none text-sm mb-6"
                            placeholder="例如：一个专为 Z 世代设计的梦核风格社交 App..."
                            value={userIdea}
                            onChange={(e) => setUserIdea(e.target.value)}
                        />
                        <div className="flex gap-3">
                            <button onClick={() => setShowIdeaInput(false)} className="flex-1 py-4 bg-gray-100 text-gray-900 font-bold rounded-2xl text-xs uppercase tracking-widest hover:bg-gray-200">取消</button>
                            <button onClick={handleCreateProject} disabled={!userIdea.trim()} className="flex-[2] py-4 bg-black text-white font-bold rounded-2xl text-xs uppercase tracking-widest hover:shadow-xl disabled:opacity-50">启动引擎</button>
                        </div>
                    </div>
                </div>
            )}

            {/* Loading Overlay */}
            {isGeneratingProject && (
                <div className="fixed inset-0 bg-white/90 z-[100] flex flex-col items-center justify-center text-black">
                    <div className="text-6xl mb-6 animate-bounce">🧠</div>
                    <h2 className="text-3xl font-black mb-2 tracking-tighter">GENESIS 引擎运行中</h2>
                    <p className="text-gray-400 font-mono text-xs uppercase tracking-[0.2em]">{generationStatus}</p>
                </div>
            )}
        </div>
    );
};

export default App;

